  "updated_at" timestamptz not null default current_timestamp,
  constraint "pk_breed_id" primary key ("id"),
  constraint "uq_breed_animal_specie_id" unique ("animal_specie_id", "name"),
  constraint "fk_breed_animal_specie_id" foreign key ("animal_specie_id") references "animal_specie" ("id") on delete cascade
);

create table "organization" (
  "id" bigint not null generated by default as identity,
  "name" varchar(255) not null,
  "website" text,
  "mission_statement" text,
  "adoption_policy" text,
  "adoption_url" text,
  "distance" varchar(20),
  "status" varchar(30) not null default 'pending',
