  constraint "fk_organization_membership_user_id" foreign key ("user_id") references "user" ("id") on delete cascade,
  constraint "ck_organization_membership_role_valid" check ("role" in ('owner', 'admin', 'member', 'volunteer')),
  constraint "ck_organization_membership_status_valid" check ("status" in ('pending', 'approved', 'rejected'))
